-- maldives_prayer_times — minimal schema for prayer-times-by-coordinates lookup
-- Contains only the two tables the app query needs:
--   tbl_islands       (202 islands that have prayer data: lat/lng + band + per-island offset)
--   tbl_prayer_times  (42 latitude bands x 366 perpetual-calendar days, year 0004 is a dummy leap year)
USE `min_prayer_times`;
SET NAMES utf8mb4;
SET sql_mode = 'NO_ENGINE_SUBSTITUTION';

DROP TABLE IF EXISTS tbl_prayer_times;
DROP TABLE IF EXISTS tbl_islands;

CREATE TABLE tbl_islands (
  island_id          smallint unsigned NOT NULL,
  reg_no             varchar(4)        DEFAULT NULL,
  name_en            varchar(255)      NOT NULL,
  lat                decimal(9,6)      NOT NULL,
  lng                decimal(9,6)      NOT NULL,
  prayer_table_id    smallint unsigned NOT NULL,
  prayer_adjust_mins tinyint           NOT NULL DEFAULT 0,
  PRIMARY KEY (island_id),
  KEY idx_table (prayer_table_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE tbl_prayer_times (
  prayer_table_id smallint unsigned NOT NULL,
  `date`          date NOT NULL,           -- year 0004 is a placeholder; match on MONTH()/DAY() only
  fajr            time NOT NULL,
  sunrise         time NOT NULL,
  duhr            time NOT NULL,
  asr             time NOT NULL,
  maghrib         time NOT NULL,
  isha            time NOT NULL,
  PRIMARY KEY (prayer_table_id, `date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

